local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGameObjsCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGameObjsCtrl = LxClass("LMatchThreeGameObjsCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------
local table                   = table
local pairs                   = pairs
local ipairs                  = ipairs
local string                  = string
local math                    = math
local tonumber                = tonumber

local ObjType                 = ModelMatchThreeGame.ObjType
local LMatchThreeGameObj      = LXImport("..Object.LMatchThreeGameObj")

local isEditor                = CS.IsUnityEdit()

-- 下落一格的时间
local OneDropNodeTime         = 0.1

-----------------------------------------------------------------
function LMatchThreeGameObjsCtrl:LMatchThreeGameObjsCtrl()
    -- gModelMatchThreeGame
    self._model = gModelMatchThreeGame

    -- 对象列表
    self._objMap = {}

    -- 临时对象列表
    self._tempObjsMap = {}

    -- 空对象列表
    self._emptyObjMap = {}

    self:InitEvent()
end

-- 销毁
function LMatchThreeGameObjsCtrl:OnDestroy()
    for i, obj in pairs(self._objMap) do
        obj:Destroy()
    end
    self._objMap = {}

    for i, obj in pairs(self._emptyObjMap) do
        obj:Destroy()
    end
    self._emptyObjMap = {}
end

-- 初始化事件
function LMatchThreeGameObjsCtrl:InitEvent()

end

-- 初始化
function LMatchThreeGameObjsCtrl:Init()
    self:InitEmptyObjs()
    self:InitMonsters()
    self:InitBomb()
    self:InitBox()
    self:InitBurrow()
end

-- 空对象初始化
function LMatchThreeGameObjsCtrl:InitEmptyObjs()
    local posCtrl = self:GetCtrl("Pos")
    local objType = ObjType.Empty

    local parent = self:GetEmptyNodeParent()
    for index in pairs(posCtrl:GetAllCanUseData()) do
        if index > 0 then
            local obj = self:CreateObj(objType, index, parent)
            obj:Refresh()
            self._emptyObjMap[index] = obj

            -- if isEditor then
            --     obj._uiData.transform.name = "empty"
            -- end
        end
    end
end

-- 初始化怪物
function LMatchThreeGameObjsCtrl:InitMonsters()
    local ref = gModelMatchThreeGame:GetRef()
    local objType = ObjType.Monster
    for _, tab in ipairs(ref.monsters) do
        local index = tab.index
        local obj = self:CreateObj(objType, index)
        obj:SetHp(tab.hp)
        obj:Refresh()
        self._objMap[index] = obj
    end
end

-- 初始化炸弹
function LMatchThreeGameObjsCtrl:InitBomb()
    local ref = gModelMatchThreeGame:GetRef()
    local objType = ObjType.Bomb
    for _, tab in ipairs(ref.bombs) do
        local index = tab.index
        local obj = self:CreateObj(objType, index)
        obj:SetHp(tab.hp)
        obj:Refresh()
        self._objMap[index] = obj
    end
end

-- 初始化箱子
function LMatchThreeGameObjsCtrl:InitBox()
    local ref = gModelMatchThreeGame:GetRef()
    local objType = ObjType.Box
    for _, tab in ipairs(ref.boxs) do
        local index = tab.index
        local obj = self:CreateObj(objType, index)
        obj:SetHp(tab.hp)
        obj:Refresh()
        self._objMap[index] = obj
    end
end

-- 初始化地洞
function LMatchThreeGameObjsCtrl:InitBurrow()
    local ref = gModelMatchThreeGame:GetRef()
    local objType = ObjType.Burrow
    for _, tab in ipairs(ref.burrows) do
        local index = tab.index
        local obj = self:CreateObj(objType, index)

        local hpList = {}
        for k, v in ipairs(tab.hpList) do
            hpList[k] = v
        end
        obj:SetMonsterRefreshWhenNum(tab.refreshWhenNum)
        obj:SetMonsterHpList(hpList)
        obj:SetMonsterPriority(tab.priority or 0)
        obj:Refresh()
        self._objMap[index] = obj
    end
end

-- 获取地图对象
function LMatchThreeGameObjsCtrl:GetObj(index)
    return self._objMap[index]
end

-- 获取地图所有对象
function LMatchThreeGameObjsCtrl:GetAllObjs()
    return self._objMap
end

-- 改变索引
function LMatchThreeGameObjsCtrl:ChangeIndex(fromIndex, toIndex)
    local obj = self._objMap[fromIndex]
    if obj then
        obj:SetIndex(toIndex)
        self._objMap[toIndex] = obj
        self._objMap[fromIndex] = nil
    end
end

-- true:表示为正常对象
function LMatchThreeGameObjsCtrl:IsNormalObj(index)
    if not index then
        return false
    end
    local obj = self._objMap[index]
    if obj then
        return obj:IsNormal()
    end
    return false
end

-- true:表示为空对象
function LMatchThreeGameObjsCtrl:IsEmpty(index)
    if not index then
        return false
    end
    local obj = self._objMap[index]
    if obj then
        return false
    end
    return self:GetCtrl("Pos"):IsValid(index)
end

-- 销毁对象
function LMatchThreeGameObjsCtrl:DestroyObj(index)
    local obj = self._objMap[index]
    if obj then
        obj:Destroy()
    end
    self._objMap[index] = nil
end

-- 删除对象
function LMatchThreeGameObjsCtrl:DeleteObj(index)
    local obj = self._objMap[index]
    self._objMap[index] = nil
    return obj
end

-- 获取当前剩余怪物数量
function LMatchThreeGameObjsCtrl:GetMonsterNum()
    local count = 0
    for _, obj in pairs(self._objMap) do
        if obj:IsMonster() then
            if obj:GetHp() > 0 then
                count = count + 1
            end
        elseif obj:IsBurrow() then
            local hpList = obj:GetMonsterHpList()
            count = count + #hpList
        end
    end
    return count
end

-- 刷新所有对象
function LMatchThreeGameObjsCtrl:RefreshAllObjs()
    for _, obj in pairs(self._objMap) do
        obj:Refresh()
    end
end

-- 死亡动画
function LMatchThreeGameObjsCtrl:PlayDead(index, time)
    local obj = self._objMap[index]
    if obj then
        obj:PlayDead(time)
    end
end

-- 改变对象状态
function LMatchThreeGameObjsCtrl:ChangeObjState(touchIndexList)
    local num = #touchIndexList
    local isHight = gModelMatchThreeGame:IsMultiClear(num)
    local map = {}
    if num >= gModelMatchThreeGame:GetClearNodeNeedNum() then
        for _, index in ipairs(touchIndexList) do
            map[index] = true
        end
    end
    for index, obj in pairs(self._objMap) do
        if map[index] then
            if isHight then
                obj:PlayHeightWhenConnect()
            else
                obj:PlayNormalWhenConnect()
            end
        else
            obj:Refresh()
        end
    end

    self:ChangeSword(touchIndexList)
    self:ChangeMonster(touchIndexList)
end

-- 改变剑的状态
function LMatchThreeGameObjsCtrl:ChangeSword(touchIndexList)
    local num = #touchIndexList
    local index = 0
    if num > 0 and not gModelMatchThreeGame:IsMultiClear(num) then
        index = touchIndexList[1]
    else
        num = 0
    end
    self:GetCtrl("Sword"):Show(index, num)
end

-- 改变怪物的状态
function LMatchThreeGameObjsCtrl:ChangeMonster(touchIndexList)
    local num = #touchIndexList
    local lastIndex = touchIndexList[num]
    local posCtrl = self:GetCtrl("Pos")

    local sadMap = {}
    if gModelMatchThreeGame:IsMultiClear(num) then
        for _, index in ipairs(touchIndexList) do
            for _, v in ipairs(posCtrl:GetAroundIndex(index)) do
                local obj = self._objMap[v]
                if obj and obj:IsMonster() then
                    sadMap[v] = true
                end
            end
        end
    elseif num >= gModelMatchThreeGame:GetClearNodeNeedNum() then
        local indexList = posCtrl:GetAroundIndex(lastIndex)
        for _, index in ipairs(indexList) do
            local obj = self._objMap[index]
            if obj and obj:IsMonster() then
                sadMap[index] = true
            end
        end
    end

    for index, obj in pairs(self._objMap) do
        if obj:IsMonster() then
            if sadMap[index] then
                obj:ShowSadMonsterIcon()
            else
                obj:Refresh()
            end
        end
    end
end

-- 创建对象
function LMatchThreeGameObjsCtrl:CreateObj(objType, index, parent)
    local posCtrl = self:GetCtrl("Pos")
    local objsPoolCtrl = self:GetCtrl("ObjsPool")
    local uiData = objsPoolCtrl:PopObj()
    local pos = posCtrl:GetPosByIndex(index)

    parent = parent or self:GetNodeParent()
    local param = {
        parent  = parent,
        uiData  = uiData,
        pos     = pos,
        index   = index,
        objType = objType,
    }
    -- if isEditor then
    uiData.transform.name = index
    -- end

    local obj = LMatchThreeGameObj:New(self)
    obj:Init(param)
    return obj
end

-- 随机生成一个正常对象
function LMatchThreeGameObjsCtrl:RandomCreateNormalObj(index)
    local objType = self:RandomNormalObjType()

    local obj = self:CreateObj(objType, index)
    return obj
end

-- 随机生成一个正常对象类型
function LMatchThreeGameObjsCtrl:RandomNormalObjType()
    if not self._normalTypeList then
        local ref = gModelMatchThreeGame:GetRef()
        local list = {}
        local weight = 0
        for _, v in ipairs(string.split(ref.colors, "|")) do
            local val = tonumber(v)
            weight = weight + val
            table.insert(list, weight)
        end
        table.sort(list, function(a, b) return a < b end)

        local typeList = gModelMatchThreeGame:RandomNormalObjTypeList(#list)
        self._normalTypeList = { weight = weight, list = list, typeList = typeList }
    end

    local data = self._normalTypeList

    local weight = math.random(100, data.weight * 100) / 100
    weight = math.floor(weight)
    for k, v in ipairs(data.list) do
        if weight <= v then
            return data.typeList[k]
        end
    end
    return data.typeList[1]
end

-- 获取节点的父节点
function LMatchThreeGameObjsCtrl:GetNodeParent()
    if not self._nodeParent then
        local root = self:GetMap():GetMapTrans()
        self._nodeParent = CS.FindTrans(root, "LayerRoot/LayerNode")
    end
    return self._nodeParent
end

-- 获取空节点的父节点
function LMatchThreeGameObjsCtrl:GetEmptyNodeParent()
    if not self._emptyNodeParent then
        local root = self:GetMap():GetMapTrans()
        self._emptyNodeParent = CS.FindTrans(root, "LayerRoot/LayerEmptyNode")
    end
    return self._emptyNodeParent
end

-- 保存当前地图所有对象到临时变量
function LMatchThreeGameObjsCtrl:SaveCurMapObjsToTemp()
    self._tempObjsMap = {}
    for index, obj in pairs(self._objMap) do
        self._tempObjsMap[index] = obj
    end
end

-- true：表示旧的对象
function LMatchThreeGameObjsCtrl:IsOld(index)
    return self._tempObjsMap[index] ~= nil
end

-- 生产正常对象
function LMatchThreeGameObjsCtrl:CreateNormalObj()
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()

    -- 保存先有
    self:SaveCurMapObjsToTemp()

    -- 原有的对象下落
    self:DropObjs()

    self:SaveCurMapObjsToTemp()

    -- 填冲满本列
    for i = 1, col do
        self:CreateTopObj(i)
    end

    self:SaveCurMapObjsToTemp()

    -- 其它可能空白的地方
    self:CreateOtherEmptyObjs()
end

-- 随机生成
function LMatchThreeGameObjsCtrl:TestRandomCreateObjs(num)
    local indexList = {}
    local posCtrl = self:GetCtrl("Pos")
    for index in pairs(posCtrl:GetAllCanUseData()) do
        if not self._objMap[index] and posCtrl:IsValid(index) then
            table.insert(indexList, index)
        end
    end

    for i = 1, num do
        local index = math.random(1, #indexList)
        local toIndex = table.remove(indexList, index)
        if toIndex then
            local obj = self:RandomCreateNormalObj(toIndex)
            obj:Refresh()
            self._objMap[toIndex] = obj
        end
    end
end

-- 固定生成
function LMatchThreeGameObjsCtrl:TestCreateObjs(index)
    local posCtrl = self:GetCtrl("Pos")
    if not self._objMap[index] and posCtrl:IsValid(index) then
        local obj = self:RandomCreateNormalObj(index)
        obj:Refresh()
        self._objMap[index] = obj
    end
end

-- 原来的对象下落 (逆向计算最优路径)
function LMatchThreeGameObjsCtrl:DropObjs()
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()

    local function DoPath(path)
        if not path then
            return
        end
        local newPath = {}
        for i = #path, 2, -1 do -- 第一个为负数，此处又必须是原来对象下落
            table.insert(newPath, 1, path[i])
            if self._objMap[path[i]] then
                break
            end
        end
        local bestPath = self:DropObjsCheckPath(newPath)
        local firstIndex = bestPath[1]
        local lastIndex = bestPath[#bestPath]

        --[[ 逆向计算，格子优先，某些情况下，本来需要本列的全部直线下落，导致旁边的格子下落到本列
        local pathList0 = self:ReverseCalculationBestPath(lastIndex, false)
        if pathList0 then
            bestPath = pathList0
            firstIndex = bestPath[1]
            lastIndex = bestPath[#bestPath]
        end
        ]]

        --[[ 模拟正常下落，但只能下落到本列及旁边的列，跨多列则无法实现
        firstIndex = bestPath[1]
        lastIndex = bestPath[#bestPath]
        local curCol = posCtrl:GetColIndex(firstIndex)
        local curRow = posCtrl:GetRowIndex(firstIndex)
        local pathList1 = self:GetDropPathListWhenLeftOrRight(curCol, curRow)
        local pathList2 = self:GetDropPathListWhenLeftOrRight(curCol, curRow, true)
        if pathList1 then
            if pathList1[#pathList1] == lastIndex then
                table.insert(pathList1, 1, firstIndex)
                bestPath = self:GetBestPath(bestPath, pathList1)
            end
        end
        if pathList2 and pathList2[#pathList2] == lastIndex then
            table.insert(pathList2, 1, firstIndex)
            bestPath = self:GetBestPath(bestPath, pathList2)
        end
        ]]

        local obj = self._objMap[firstIndex]
        if obj then
            local newIndex = bestPath[#bestPath]
            obj:SetIndex(newIndex)
            obj:SetDropPathList(bestPath)
            obj:ShowObj(false)
            self._objMap[firstIndex] = nil
            self._tempObjsMap[firstIndex] = nil
            self._objMap[newIndex] = obj
        end
    end

    for _, index in ipairs(posCtrl:GetReverseIndexList()) do
        if not self._objMap[index] then
            local preIndex = index - 1
            local preFontIndex = preIndex - col

            local needPre = false
            if posCtrl:IsValid(preIndex) and not self._objMap[preIndex] and posCtrl:IsValid(preFontIndex) and
                (not self._objMap[preFontIndex] or self:IsNormalObj(preFontIndex)) then
                if posCtrl:GetRowIndex(index) == posCtrl:GetRowIndex(preIndex) then
                    needPre = true
                end
            end

            local path = self:ReverseCalculationBestPath(index, true)

            if path then
                local count = #path
                if needPre and path[count - 1] == preFontIndex then
                    path = self:ReverseCalculationBestPath(preIndex, true)
                    DoPath(path)

                    path = self:ReverseCalculationBestPath(index, true)
                end
                DoPath(path)
            end
        end
    end
end

-- 由于逆向计算路径，向上优先，某些情况导致某些格子应该早下落，反而不落，如：
--[[
10 9
16 17
22 23
28 29

:10:16为正常格子
:29:23:27 为空
:其它不阻档
29的空格子，应该由：16->23->29, 但逆向计算，向上优先，得出：29->23->17->10
故此函数为了校正以上情况。（只取本列即可，其它列肯定非优先路径）
]]
function LMatchThreeGameObjsCtrl:DropObjsCheckPath(path)
    local posCtrl = self:GetCtrl("Pos")
    local firstIndex = path[1]
    local map = {}
    for _, v in ipairs(path) do
        map[v] = true
    end

    local curCol = posCtrl:GetColIndex(firstIndex)
    local indexList = posCtrl:GetColIndexList(curCol)

    local checkIndexList = {}
    local startIndex
    for k, index in ipairs(indexList) do
        if startIndex then
            local obj = self._objMap[index]
            if obj then
                if obj:IsNormal() then
                    table.insert(checkIndexList, 1, index)
                else
                    break
                end
            end
        end
        if index == firstIndex then
            startIndex = index
        end
    end

    local col = posCtrl:GetCol()
    local canIndex, fromIndex
    for _, index in ipairs(checkIndexList) do
        local leftIndex = index - 1 + col
        local rightIndex = index + 1 + col
        -- if posCtrl:GetRowIndex(leftIndex) ~= curRow or not posCtrl:IsValid(leftIndex) then
        --     leftIndex = nil
        -- end
        -- if posCtrl:GetRowIndex(rightIndex) ~= curRow or not posCtrl:IsValid(rightIndex) then
        --     rightIndex = nil
        -- end
        if map[leftIndex] then
            canIndex = index
            fromIndex = leftIndex
            break
        end
        if map[rightIndex] then
            canIndex = index
            fromIndex = rightIndex
            break
        end
    end

    local newPath = path
    if canIndex then
        newPath = { canIndex }
        local canAdd = false
        for k, v in ipairs(path) do
            if v == fromIndex then
                canAdd = true
            end
            if canAdd then
                table.insert(newPath, v)
            end
        end
    end

    return newPath
end

-- 固定顶部生成对象填冲满本列
function LMatchThreeGameObjsCtrl:CreateTopObj(curCol, fillType)
    local posCtrl = self:GetCtrl("Pos")

    -- 第一行的id列表
    local indeList = posCtrl:GetRowIndexList(1)
    local index = indeList[curCol]

    for i = 1, posCtrl:GetTotal() do
        if self._objMap[index] or not posCtrl:IsValid(index) then
            -- 第一个已填满，则停止
            break
        end

        local pathList = self:GetDropPathListWhenLeftOrRight(curCol, 0, false, true)
        if #pathList > 0 then
            local newIndex = pathList[#pathList]
            table.insert(pathList, 1, -curCol)


            --if not posCtrl:IsValid(newIndex) then
            --Log("有误：", pathList, newIndex, curCol)
            --pathList = self:GetDropPathListWhenLeftOrRight(curCol, 0, false, true)
            --end

            local obj = self:RandomCreateNormalObj(newIndex)
            obj:Refresh()
            obj:SetDropPathList(pathList)
            obj:ShowObj(false)
            self._objMap[newIndex] = obj
        end
    end
end

-- 以正常方式生成，可能会产生空白的地方，此时需要逆向计算路径，以生成对象
function LMatchThreeGameObjsCtrl:CreateOtherEmptyObjs()
    local posCtrl = self:GetCtrl("Pos")
    for _, index in pairs(posCtrl:GetReverseIndexList()) do
        if not self._objMap[index] and posCtrl:IsValid(index) then
            local pathList = self:ReverseCalculationDropPathAll(index, nil, true)

            if pathList then
                local obj = self:RandomCreateNormalObj(index)
                obj:Refresh()
                obj:SetDropPathList(pathList)
                obj:ShowObj(false)
                self._objMap[index] = obj

                if pathList[1] > 0 then
                    if LOG_INFO_ENABLED then
                        gModelMatchThreeGame:Log("逆向计算路径，节点有误，初始节点不为空:" .. index)
                    end
                end
            end
        end
    end
end

-- 获取掉路径: 只填冲满本列
function LMatchThreeGameObjsCtrl:GetDropPathListWhenNone(col, index)
    local posCtrl = self:GetCtrl("Pos")
    local list = posCtrl:GetColIndexList(col)

    local pathList = {}
    for i = index + 1, #list do
        if not self._objMap[list[i]] then
            table.insert(pathList, list[i])
        else
            -- 有对象，则停止
            break
        end
    end
    return pathList
end

-- 获取掉路径: 只填冲满本列和左则 或 只填冲满本列和右则
function LMatchThreeGameObjsCtrl:GetDropPathListWhenLeftOrRight(col, rowIndex, isLeft, ignoreNormal)
    local posCtrl = self:GetCtrl("Pos")
    local list = posCtrl:GetColIndexList(col)
    local listOut = {}
    if isLeft then
        listOut = posCtrl:GetColIndexList(col - 1)
    else
        listOut = posCtrl:GetColIndexList(col + 1)
    end
    local pathList = {}
    local outSide = false
    for i = rowIndex + 1, #list do
        if not outSide then
            if not self._objMap[list[i]] and posCtrl:IsValid(list[i]) then
                table.insert(pathList, list[i])
            else
                -- 有对象，外则有空位
                if listOut[i] and posCtrl:IsValid(listOut[i]) and not self._objMap[listOut[i]] then
                    local flag
                    if isLeft then
                        flag = outSide and 1 or -1
                    else
                        flag = outSide and -1 or 1
                    end

                    local path = self:ReverseCalculationDropPath(listOut[i], flag, nil, ignoreNormal)
                    if not path then
                        -- 只有这里能走
                        table.insert(pathList, listOut[i])
                        outSide = true
                    else
                        table.insert(pathList, listOut[i])
                        outSide = true
                        table.remove(path, 1)
                        local weight1 = self:GetPathWeight(path)
                        local weight2 = self:GetPathWeight(pathList)
                        if weight2 > weight1 then
                            -- 选择外部路径
                            table.remove(pathList, #pathList)
                            outSide = false
                            break
                        end
                    end
                else
                    break
                end
            end
        else
            -- 已在外侧，向下优先，有阻档则回内侧
            if not self._objMap[listOut[i]] and posCtrl:IsValid(listOut[i]) then
                table.insert(pathList, listOut[i])
            else
                if not self._objMap[list[i]] and posCtrl:IsValid(list[i]) then
                    table.insert(pathList, list[i])
                    outSide = false
                else
                    -- 有对象，则停止
                    break
                end
            end
        end
    end
    return pathList
end

-- 获取掉路径: 填冲满本列和左右则, 左则优先
function LMatchThreeGameObjsCtrl:GetDropPathListWhenLeftAndRight(col, index)
    local posCtrl = self:GetCtrl("Pos")
    local list = posCtrl:GetColIndexList(col)
    local listLeft = posCtrl:GetColIndexList(col - 1)
    local listRight = posCtrl:GetColIndexList(col + 1)

    local pathList = {}

    -- -1,为左，0为本列，1为右
    local flag = 0
    for i = index + 1, #list do
        if flag == 0 then
            if not self._objMap[list[i]] then
                table.insert(pathList, list[i])
            else
                -- 有对象，则先左后右判断
                if listLeft[i] and posCtrl:IsValid(listLeft[i]) and not self._objMap[listLeft[i]] then
                    table.insert(pathList, listLeft[i])
                    flag = -1
                elseif listRight[i] and posCtrl:IsValid(listRight[i]) and not self._objMap[listRight[i]] then
                    table.insert(pathList, listRight[i])
                    flag = 1
                else
                    -- 左右都没有空位，则停止
                    break
                end
            end
        elseif flag == -1 then
            -- 在左侧，向下优先，有阻档则右滑
            if not self._objMap[listLeft[i]] then
                table.insert(pathList, listLeft[i])
            else
                if not self._objMap[list[i]] then
                    table.insert(pathList, list[i])
                    flag = 0
                else
                    -- 有对象，停止
                    break
                end
            end
        else
            -- 在右侧，向下优先，有阻档则左滑
            if not self._objMap[listRight[i]] then
                table.insert(pathList, listRight[i])
            else
                if not self._objMap[list[i]] then
                    table.insert(pathList, list[i])
                    flag = 0
                else
                    -- 有对象，停止
                    break
                end
            end
        end
    end
end

-- 反向计算掉落路径 (所有方向)
function LMatchThreeGameObjsCtrl:ReverseCalculationDropPathAll(index, hadGoMap, ignoreNormal)
    local pathList = self:ReverseCalculationDropPath(index, 1, hadGoMap, ignoreNormal)
    if not pathList then
        pathList = self:ReverseCalculationDropPath(index, -1, hadGoMap, ignoreNormal)
    else
        local pathList2 = self:ReverseCalculationDropPath(index, -1, hadGoMap, ignoreNormal)
        if pathList2 then
            -- 两条路径都有，则取最优路径
            pathList = self:GetBestPath(pathList, pathList2)
        end
    end
    if not pathList then
        pathList = self:ReverseCalculationDropPath(index, 0, hadGoMap, ignoreNormal)
    end
    return pathList
end

-- 反向计算掉落路径,优先级：先上，再则边, 返回nil，表示没有路径
-- index:开始的节点
-- flag:0,表示可向左或右， -1:表示只向左， 1:表示只向右
-- hadGoMap：已走过节点（向上为最优先，只有在左右时，才判断，但当另一边不可走的，则走已走过的节点）
-- ignoreNormal: true:表示忽略正常节点，除非遇到障碍，否则一直到最顶(负数的那个)
function LMatchThreeGameObjsCtrl:ReverseCalculationDropPath(index, flag, hadGoMap, ignoreNormal)
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()
    local row = posCtrl:GetRow()
    local curRow = posCtrl:GetRowIndex(index)

    local curIndex = index
    local pathList = { index }
    local failMap = {}

    local hadGo = {}
    for index in pairs(hadGoMap or {}) do
        hadGo[index] = 0
    end

    local function GoBack()
        -- 回退一格
        if #pathList > 1 then
            local failIndex = table.remove(pathList)
            curRow = curRow + 2
            failMap[failIndex] = true
            curIndex = pathList[#pathList]
            return true
        else
            return false
        end
    end

    local function CheckUp()
        -- 返回大于0:表示能向上移动一格
        local curCol = posCtrl:GetColIndex(curIndex)
        local colIndexList = posCtrl:GetColIndexList(curCol)

        local toIndex = colIndexList[curRow]
        if failMap[toIndex] then
            return -1, toIndex
        end

        if not posCtrl:IsValid(toIndex) then
            return -1, toIndex
        end

        local oldObj = self._tempObjsMap[toIndex]
        if oldObj then
            if oldObj:IsNormal() then
                if ignoreNormal then
                    return 1, toIndex
                end
                table.insert(pathList, toIndex)
                curIndex = toIndex
                return 0, toIndex
            end
            return -1, toIndex
        end

        return 1, toIndex
    end

    local function CheckUpSide(isLeft, ignoreGo)
        -- 返回大于0:表示能向上则边移动一格
        local curCol = posCtrl:GetColIndex(curIndex)
        local colIndexList = posCtrl:GetColIndexList(curCol + (isLeft and -1 or 1))

        local toIndex = colIndexList[curRow]
        if not toIndex then
            return -1, toIndex
        end

        if failMap[toIndex] then
            return -1, toIndex
        end

        if not posCtrl:IsValid(toIndex) then
            return -1, toIndex
        end

        if flag == 0 then
            if hadGo[toIndex] and not ignoreGo then
                return -1, toIndex
            end
        end

        local oldObj = self._tempObjsMap[toIndex]
        if oldObj then
            if oldObj:IsNormal() then
                if ignoreNormal then
                    return 1, toIndex
                end
                table.insert(pathList, toIndex)
                curIndex = toIndex
                return 0, toIndex
            end
            return -1, toIndex
        end

        return 1, toIndex
    end


    local function CheckUpSideAll()
        -- 判断左右两边
        local ok, toIndex = CheckUpSide(true)
        local hasSet = false
        if ok == 0 then
            return ok, toIndex, hasSet
        end

        if ok == 1 then
            table.insert(pathList, toIndex)
            curIndex = toIndex
            hasSet = true
            return ok, toIndex, hasSet
        end

        ok, toIndex = CheckUpSide(false)
        if ok == 0 then
            return ok, toIndex, hasSet
        end

        if ok == 1 then
            table.insert(pathList, toIndex)
            curIndex = toIndex
            hasSet = true
            return ok, toIndex, hasSet
        end

        -- 第二次，忽略走过的节点
        local ok, toIndex = CheckUpSide(true, true)
        local hasSet = false
        if ok == 0 then
            return ok, toIndex, hasSet
        end

        if ok == 1 then
            table.insert(pathList, toIndex)
            curIndex = toIndex
            hasSet = true
            return ok, toIndex, hasSet
        end

        ok, toIndex = CheckUpSide(false, true)
        if ok == 0 then
            return ok, toIndex, hasSet
        end

        if ok == 1 then
            table.insert(pathList, toIndex)
            curIndex = toIndex
            hasSet = true
            return ok, toIndex, hasSet
        end
    end


    for i = 1, posCtrl:GetTotal() * 5 do -- 随意估值
        if curRow == 1 then
            break
        end

        curRow = curRow - 1
        -- ok:-1 失败，0：结束，1：需要添加
        local ok, toIndex

        local hasSide = false
        if not ignoreNormal then
            -- 有格子优先
            -- 1，2，3 为 curIndex 顶部的三个格子
            local curCol = posCtrl:GetColIndex(curIndex)
            local curRow = posCtrl:GetRowIndex(curIndex) - 1
            local twoIndex = curIndex - col
            local oneIndex = twoIndex - 1
            local threeIndex = twoIndex + 1
            if posCtrl:GetRowIndex(oneIndex) ~= curRow or not posCtrl:IsValid(oneIndex) then
                oneIndex = nil
            end
            if posCtrl:GetRowIndex(threeIndex) ~= curRow or not posCtrl:IsValid(threeIndex) then
                threeIndex = nil
            end

            if twoIndex and self._objMap[twoIndex] then
                ok, toIndex = CheckUp()
            elseif flag == -1 and self:IsNormalObj(oneIndex) then
                ok, toIndex = CheckUpSide(true, true)
                hasSide = true
            elseif flag == 1 and self:IsNormalObj(threeIndex) then
                ok, toIndex = CheckUpSide(false, true)
                hasSide = true
            elseif flag == 0 and (self:IsNormalObj(oneIndex) or self:IsNormalObj(threeIndex)) then
                if self:IsNormalObj(oneIndex) then
                    ok, toIndex = CheckUpSide(true, true)
                    hasSide = true
                elseif self:IsNormalObj(threeIndex) then
                    ok, toIndex = CheckUpSide(false, true)
                    hasSide = true
                end
            end
        end
        if ok == nil then
            ok, toIndex = CheckUp()
        end

        if ok == 0 then
            break
        end

        if ok == 1 then
            table.insert(pathList, toIndex)
            curIndex = toIndex
        elseif not hasSide then
            -- 检查向边移动
            local hasSet = false
            if flag == -1 then
                ok, toIndex = CheckUpSide(true)
            elseif flag == 1 then
                ok, toIndex = CheckUpSide(false)
            else
                ok, toIndex, hasSet = CheckUpSideAll()
            end

            if ok == 0 then
                break
            end

            if not hasSet then
                if ok == 1 then
                    table.insert(pathList, toIndex)
                    curIndex = toIndex
                else
                    -- 不能向则边移动，则回退一格
                    if not GoBack() then
                        break
                    end
                end
            end
        end
    end

    if #pathList == 1 then
        return nil
    end
    table.sort(pathList, function(a, b) return a < b end)


    local first = pathList[1]
    local col = posCtrl:GetCol()
    if first <= col then
        if ignoreNormal then
            table.insert(pathList, 1, -first)
        elseif not self._tempObjsMap[first] then
            table.insert(pathList, 1, -first)
        end
    end



    return pathList
end

-- 逆向计算最优路径
function LMatchThreeGameObjsCtrl:ReverseCalculationBestPath(index, ignoreNormal)
    local path = self:ReverseCalculationDropPathAll(index, nil, ignoreNormal)
    if not path then
        return nil
    end
    local bestPath = path
    local map = {}
    for i = 1, 4 do
        -- 为了效率，最多只尝试4种
        for i, v in ipairs(path) do
            map[v] = true
        end
        path = self:ReverseCalculationDropPath(index, 0, map, ignoreNormal)
        if not path then
            break
        end
        bestPath = self:GetBestPath(bestPath, path)
    end
    return bestPath
end

-- 反向计算由节点变动，引起另一个节点的变化 (传进来的index节点，开始时必定是空)
function LMatchThreeGameObjsCtrl:ReverseCalculationChangeNode(index)
    local posCtrl = self:GetCtrl("Pos")
    local row = posCtrl:GetRow()
    local col = posCtrl:GetCol()
    local oldIndex = index

    for i = 1, row do
        if index <= col then
            -- 最顶行
            local obj = self._objMap[index]
            if obj then
                break
            end
            obj = self:RandomCreateNormalObj(index)
            obj:Refresh()
            obj:SetDropPathList({ -index })
            obj:ShowObj(false)
            self._objMap[index] = obj
            return
        end

        local pathList = self:ReverseCalculationDropPathAll(index)
        if not pathList then
            break
        end
        local firstIndex = pathList[1]
        local obj = self._objMap[firstIndex]
        if obj then
            local path = obj:GetDropPathList()
            if path and #path > 0 then
                if path[1] < 0 then
                    for i = #path - 1, 1, -1 do
                        table.insert(pathList, 1, path[i])
                    end

                    local newObj = self:RandomCreateNormalObj(index)
                    newObj:Refresh()
                    newObj:SetDropPathList(pathList)
                    newObj:ShowObj(false)
                    self._objMap[index] = obj
                    return
                end
                for i = #path - 1, 1, -1 do
                    table.insert(pathList, 1, path[i])
                end
            end
            self._objMap[firstIndex] = obj
            self._tempObjsMap[firstIndex] = nil

            obj:SetDropPathList(pathList)
            obj:ShowObj(false)
            self._objMap[index] = obj

            index = pathList[1]
        else
            Log("此处不应该出现！开始index:", oldIndex, "当前index:", index)
        end
    end
end

-- 获取路径的权重(越小，越好)
function LMatchThreeGameObjsCtrl:GetPathWeight(pathList)
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()
    local weight = 0

    --[[ 以最大转折点
    local colIndex = posCtrl:GetColIndex(pathList[#pathList])
    for i = 1, #pathList - 1 do
        local toIndex = pathList[i]
        if toIndex > 0 then
            local curCol = posCtrl:GetColIndex(toIndex)
            weight = math.max(weight, math.abs(curCol - colIndex))
        end
    end
    ]]

    -- 以直接节点和转折点算总权重
    local direct = 1 -- 直接节点权重
    local turn = 2   -- 转折节点权重

    local preIndex = pathList[#pathList]
    weight = direct

    for i = #pathList - 1, 1, -1 do
        local curIndex = pathList[i]
        if curIndex > 0 then
            if math.abs(curIndex - preIndex) == col then
                weight = weight + direct
            else
                weight = weight + turn
            end
        else
            -- 不要加负的,某些情况，路径未完全计算完，还有添加负值的情况，需要此函数计算权重
            -- weight = weight + direct
        end
        preIndex = curIndex
    end
    return weight
end

-- 获取最优路径
function LMatchThreeGameObjsCtrl:GetBestPath(pathList1, pathList2)
    local weight1 = self:GetPathWeight(pathList1)
    local weight2 = self:GetPathWeight(pathList2)
    if weight1 < weight2 then
        return pathList1
    end
    return pathList2
end

-- ture:表示路径相同
function LMatchThreeGameObjsCtrl:IsSamePath(pathList1, pathList2)
    for k, v in ipairs(pathList1) do
        if v ~= pathList2[k] then
            return false
        end
    end
    return #pathList1 == #pathList2
end

-- ture:表示路径为子路径（即pathList1为pathList2的子集）
function LMatchThreeGameObjsCtrl:IsSubPath(pathList1, pathList2)
    for k, v in ipairs(pathList1) do
        if v ~= pathList2[k] then
            return false
        end
    end
    return true
end

-- 播正常对象下落
function LMatchThreeGameObjsCtrl:PlayNormalObjDropDown()
    local outSideMap = {}
    local inSideMap = {}
    local total = 0

    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()


    for _, obj in pairs(self._objMap) do
        local path = obj:GetDropPathList() or {}
        local count = #path
        if count > 0 then
            local map = outSideMap
            local first = path[1]
            local last = path[count]
            if first > 0 then
                map = inSideMap
            end

            if not map[first] then
                map[first] = {}
            end

            local lastTurn = 0
            if count > 1 then
                local pre = path[count - 1]
                if last - pre ~= col then
                    lastTurn = 1
                end
            end

            table.insert(map[first], { obj = obj, fisrt = first, last = last, count = count, lastTurn = lastTurn })

            total = total + 1
        end
    end

    local function Sort(a, b)
        if a.count == b.count then
            if a.lastTurn ~= b.lastTurn then
                return a.lastTurn < b.lastTurn
            end
            return a.last < b.last
        end
        return a.last > b.last
    end

    for k, v in pairs(outSideMap) do
        table.sort(v, Sort)
    end
    for k, v in pairs(inSideMap) do
        table.sort(v, Sort)
    end

    local function endFunc()
        total = total - 1
        if total == 0 then
            self:PlayNormalObjDropDownFinish()
        end
        if total <= 2 then
            self._mgr:VibrateStop()
        end
    end

    local delay = 0
    for _, v in pairs(outSideMap) do
        delay = 0
        for k, tab in ipairs(v) do
            local obj = tab.obj
            obj:DropDown(delay, OneDropNodeTime, endFunc)
            delay = delay + OneDropNodeTime * 1
        end
    end

    for _, v in pairs(inSideMap) do
        for _, tab in ipairs(v) do
            local obj = tab.obj
            obj:DropDown(0, OneDropNodeTime, endFunc)
        end
    end

    if total == 0 then
        self:PlayNormalObjDropDownFinish()
    else
        -- self._mgr:VibrateTimes(10)
    end
end

-- 播正常对象下落完成
function LMatchThreeGameObjsCtrl:PlayNormalObjDropDownFinish()
    self:GetMgr():OnPlayNormalObjDropDownFinish()
end

-- 怪物移动
function LMatchThreeGameObjsCtrl:PlayMonsterMove()
    local total = 0
    local function finish()
        total = total - 1
        if total == 0 then
            self:PlayMonsterMoveEnd()
        end
    end

    local toMap = self:GetMonsterMoveToIndexMap()
    for toIndex, obj in pairs(toMap) do
        local oldObj = self:GetObj(toIndex)
        if oldObj and not oldObj:IsMonster() then
            self:DeleteObj(toIndex)
            oldObj:PlayDead(nil, nil)
        end
    end

    local fromMap = {}
    for toIndex, obj in pairs(toMap) do
        total = total + 1
        self._objMap[toIndex] = obj
        local fromIndex = obj:GetIndex()
        fromMap[fromIndex] = true
        obj:SetIndex(toIndex)
        obj:JumpTo(toIndex, nil, function() 
            finish()
        end)
    end

    for fromIndex in pairs(fromMap) do
        if not toMap[fromIndex] then
            self._objMap[fromIndex] = nil
        end
    end

    if total == 0 then
        self:PlayMonsterMoveEnd()
    end
end

-- 获取需要移动的怪物列表
function LMatchThreeGameObjsCtrl:GetMonsterMoveToIndexMap()
    local posCtrl = self:GetCtrl("Pos")

    local tempMap = {}
    local checkNum = 0
    for index, obj in pairs(self._objMap) do
        if obj:IsMonster() then
            tempMap[index] = obj
            checkNum = checkNum + 1
        end
    end

    local needMoveMap = {}
    local hadMap = {}
    local canMap = {}

    local funcList = {
        function(...) return self:MonsterMoveUp(...) end,
        function(...) return self:MonsterMoveMiddle(...) end,
        function(...) return self:MonsterMoveSide(...) end,
    }
    local funcIndex = 1

    for j = 1, posCtrl:GetTotal() do
        for i = 1, checkNum do
            local noChange = true
            for index, obj in pairs(tempMap) do
                local fromIndex = index
                local toIndex = funcList[funcIndex](index, hadMap, canMap)
                if toIndex then
                    hadMap[toIndex] = true
                    canMap[fromIndex] = true
                    tempMap[index] = nil
                    needMoveMap[toIndex] = obj

                    checkNum = checkNum - 1
                    noChange = false
                    
                    if funcIndex ~= 1 then
                        funcIndex = 1
                        break
                    end
                end
            end
            if noChange then
                break
            end
        end
        if checkNum == 0 then
            break
        end

        funcIndex = funcIndex + 1
        if not funcList[funcIndex] then
            break
        end
    end
    return needMoveMap
end

-- 怪物向上移动
function LMatchThreeGameObjsCtrl:MonsterMoveUp(index, hadMap, canMap)
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()

    local toIndex = index - col

    if self:IsNormalObj(toIndex) or self:IsEmpty(toIndex) or canMap[toIndex] then
        if not hadMap[toIndex] then
            return toIndex
        end
    end
    return nil
end

-- 怪物向中间移动
function LMatchThreeGameObjsCtrl:MonsterMoveMiddle(index, hadMap, canMap)
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()

    local toIndex

    local curCol = posCtrl:GetColIndex(index)
    if curCol == col then
        toIndex = index - 1
    elseif curCol == 1 then
        toIndex = index + 1
    elseif curCol > 3 then
        toIndex = index - 1
    else
        toIndex = index + 1
    end

    if self:IsNormalObj(toIndex) or self:IsEmpty(toIndex) or canMap[toIndex] then
        if not hadMap[toIndex] then
            return toIndex
        end
    end
    return nil
end

-- 怪物向两边移动
function LMatchThreeGameObjsCtrl:MonsterMoveSide(index, hadMap, canMap)
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()

    local toIndex

    local curCol = posCtrl:GetColIndex(index)
    if curCol == col then
        toIndex = index - 1
    elseif curCol == 1 then
        toIndex = index + 1
    elseif curCol > 3 then
        toIndex = index + 1
    else
        toIndex = index - 1
    end

    if self:IsNormalObj(toIndex) or self:IsEmpty(toIndex) or canMap[toIndex] then
        if not hadMap[toIndex] then
            return toIndex
        end
    end
    return nil
end

function LMatchThreeGameObjsCtrl:PlayMonsterMoveMap()
end

-- 怪物移动结束
function LMatchThreeGameObjsCtrl:PlayMonsterMoveEnd()
    gModelMatchThreeGame:Log("怪物移动结束")

    local total = 0
    local function finish()
        total = total - 1

        if total == 0 then
            self:PlayMonsterMoveFinish()
        end
    end

    local curMonsterNum = 0
    local burrowsMap = {}
    local posCtrl = self:GetCtrl("Pos")
    local mainRoleCtrl = self:GetCtrl("MainRole")
    local col = posCtrl:GetCol()
    local delayTime = 0
    for index, obj in pairs(self._objMap) do
        if obj:IsMonster() then
            if index <= col then
                total = total + 1
                -- 主角扣血
                local hurt = obj:GetHp()
                obj:PlayDead(nil, finish)

                local over = mainRoleCtrl:Hurt(hurt, delayTime)
                delayTime = delayTime + 0.5
                if over then
                    return
                end
            else
                curMonsterNum = curMonsterNum + 1
            end
        elseif obj:IsBurrow() then
            burrowsMap[index] = obj
        end
    end

    -- 生成怪物
    local burrowList = self:GetNeedBurrowList(burrowsMap)
    for _, obj in ipairs(burrowList) do
        local hp = obj:PopMonsterHp(curMonsterNum)
        if hp then
            curMonsterNum = curMonsterNum + 1
            total = total + 1
            local index = obj:GetIndex()
            self:BurrowCreateMonster(index, hp, finish)
        end
    end

    if total == 0 then
        self:PlayMonsterMoveFinish()
    end
end

-- 获取当前需要出怪的地洞列表
function LMatchThreeGameObjsCtrl:GetNeedBurrowList(burrowsMap)
    local priorityMax = 0
    local map = {}
    for index, obj in pairs(burrowsMap) do
        local priority = obj:GetMonsterPriority()
        if not map[priority] then
            map[priority] = {}
        end
        table.insert(map[priority], obj)
        local hpList = obj:GetMonsterHpList()
        if #hpList > 0 and priority > priorityMax then
            priorityMax = priority
        end
    end
    return map[priorityMax] or {}
end

-- 地洞生成怪物
function LMatchThreeGameObjsCtrl:BurrowCreateMonster(fromIndex, hp, endFunc)
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()
    local toIndex = fromIndex - col
    local obj = self:CreateObj(ObjType.Monster, toIndex)
    obj:SetHp(hp)
    obj:Refresh()

    local oldObj = self:DeleteObj(toIndex)
    if oldObj then
        oldObj:PlayDead(nil, nil)
    end

    self._objMap[toIndex] = obj

    local trans = obj:GetTransform()
    trans.position = posCtrl:GetPosByIndex(fromIndex)
    trans.localScale = Vector3(0.2, 0.2, 0.2)

    obj:JumpAndScaleTo(toIndex, nil, endFunc)
end

-- 怪物所有操作结束
function LMatchThreeGameObjsCtrl:PlayMonsterMoveFinish()
    gModelMatchThreeGame:Log("怪物所有操作结束")
    self:GetMgr():OnPlayMonsterMoveFinish()
end

-- 获取怪物下一个可移动的位置
function LMatchThreeGameObjsCtrl:GetMonsterNextIndex(index, hadMap, canMap)
    local posCtrl = self:GetCtrl("Pos")
    local col = posCtrl:GetCol()

    local upIndex = index - col

    if self:IsNormalObj(upIndex) or self:IsEmpty(upIndex) or canMap[upIndex] then
        if not hadMap[upIndex] then
            return upIndex
        end
    end

    local leftIndex = index - 1
    local rightIndex = index + 1

    local curCol = posCtrl:GetColIndex(index)
    if curCol == col then
        if self:IsNormalObj(leftIndex) or self:IsEmpty(leftIndex) then
            if not hadMap[leftIndex] then
                return leftIndex
            end
        end
        return nil
    end

    if curCol == 1 then
        if self:IsNormalObj(rightIndex) or self:IsEmpty(rightIndex) then
            if not hadMap[rightIndex] then
                return rightIndex
            end
        end
        return nil
    end

    if curCol > 3 and (self:IsNormalObj(leftIndex) or self:IsEmpty(leftIndex)) then
        if not hadMap[leftIndex] then
            return leftIndex
        end
    end

    if curCol <= 3 and (self:IsNormalObj(rightIndex) or self:IsEmpty(rightIndex)) then
        if not hadMap[rightIndex] then
            return rightIndex
        end
    end


    if self:IsNormalObj(leftIndex) or self:IsEmpty(leftIndex) then
        if not hadMap[leftIndex] then
            return leftIndex
        end
    end
    if self:IsNormalObj(rightIndex) or self:IsEmpty(rightIndex) then
        if not hadMap[rightIndex] then
            return rightIndex
        end
    end
    return nil
end

return LMatchThreeGameObjsCtrl
